    if (detailModel.name.length == 0) {
        detailModel.name = dualApp.name;
    }
    if (detailModel.track_id.length == 0) {
        detailModel.track_id = dualApp.trackId;
    }
    if (detailModel.bundle_id.length == 0) {
        detailModel.bundle_id = dualApp.bundleId;
    }
    if (detailModel.icon_url.length == 0) {
        detailModel.icon_url = dualApp.iconURL;
    }
    if (detailModel.subtitle.length == 0) {
        detailModel.subtitle = dualApp.subtitle;
    }
    if (detailModel.artist_name.length == 0) {
        detailModel.artist_name = dualApp.artistName;
