- (void)queryVAppWithId:(NSInteger)vappId needsFlushLocalStorage:(BOOL)needsFlush next:(void (^)(WBVAppModel * _Nullable vapp, NSError * _Nullable error))nextHandler {
    WBVAppModel *localVapp = nil;
    for(WBVAppModel* vapp in self.myApps) {
        if (vapp.vid != vappId) continue;
        if (!nextHandler) return;
        if (!needsFlush) return nextHandler(vapp, nil);
        localVapp = vapp;
        break;
    }
    NSString *oaaVersion = [[NSString alloc] initWithFormat:@"%s", oaa_version()];
    [[WBNetworkManager defaultManager] getLatestVappInfoWithVappId:vappId oaaVersion:oaaVersion callback:^(WBVAppDetailHttpModel * _Nullable requestedVapp, NSError * _Nullable error) {
        WBVAppModel *resVapp = localVapp;
        if (error) return nextHandler(nil, error);
        if (!resVapp) {
            resVapp = [WBVAppModel initWithVAppDetailModel:requestedVapp];
        } else {
            [resVapp updateWithVAppDetailModel:requestedVapp];
        }
        nextHandler(resVapp, nil);
    }];
}

